  editMode,
  setEditMode,
  validators,
  dispatchers,
  tentativeCardId,
  dragHandleListeners,
  dragHandleAttributes,
  searchMatches,
  searchQuery,
  searchCaseSensitive,
  className,
}: {
  tree: RichCardTree;
  title: string | undefined;
  titleId: string;
  collapsed: boolean;
  canCollapse: boolean;
  meta?: Record<string, FlatFieldValue>;
  metaPresentation: "hidden" | "inline" | "popover";
  metaRenderers?: Record<string, MetaRenderer>;
  onToggleCollapse: () => void;
  onSelect: (event: { shiftKey?: boolean; metaKey?: boolean; ctrlKey?: boolean }) => void;
  editable: boolean;
  canEdit: boolean;
  canRemove: boolean;
  canDuplicate: boolean;
  canDrag: boolean;
  isLocked: boolean;
  isRoot: boolean;
  allowRootRemoval: boolean;
  hasChildren: boolean;
  defaultDeletePolicy: "cascade" | "promote";
  editMode: EditMode | null;
  setEditMode: (m: EditMode | null) => void;
  validators: EditValidators;
  dispatchers: EditDispatchers;
  tentativeCardId: string | null;
  dragHandleListeners?: Record<string, (event: unknown) => void>;
  dragHandleAttributes?: Record<string, unknown>;
  searchMatches: readonly SearchMatch[];
  searchQuery: string;
  searchCaseSensitive: boolean;
  className?: string;
}) {
  const showInlineMeta =
    metaPresentation === "inline" && meta && Object.keys(meta).length > 0;
  const hasMeta = meta && Object.keys(meta).length > 0;
  const isEditingTitle =
    editable &&
    canEdit &&
    editMode?.kind === "card-title" &&
    editMode.cardId === tree.id;

  const canRenameTitle = editable && canEdit && !isRoot;
  const titleRanges = title
    ? rangesFor(searchMatches, title, tree.id, "title", undefined, searchQuery, searchCaseSensitive)
    : [];

  return (
    <div
      className={cn("flex items-center gap-1.5", className)}
      onClick={(e) => {
        if (e.target === e.currentTarget) {
          onSelect({ shiftKey: e.shiftKey, metaKey: e.metaKey, ctrlKey: e.ctrlKey });
        }
      }}
    >
      {/* Drag handle (edit mode only) */}
      {editable && canDrag ? (
        <DragHandle
          listeners={dragHandleListeners}
          attributes={dragHandleAttributes}
          disabled={!canDrag}
        />
      ) : null}

      {canCollapse ? (
        <button
          type="button"
          onClick={(e) => {
            e.stopPropagation();
            onToggleCollapse();
          }}
          aria-label={collapsed ? "Expand card" : "Collapse card"}
          aria-expanded={!collapsed}
          className="inline-flex size-5 shrink-0 items-center justify-center rounded text-muted-foreground transition-colors hover:bg-muted hover:text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
        >
          <ChevronRight
            className={cn(
              "size-3.5 transition-transform duration-150",
              !collapsed && "rotate-90",
            )}
          />
        </button>
      ) : (
        <span aria-hidden="true" className="inline-block size-5 shrink-0" />
      )}

      {isLocked ? (
        <Lock
          className="size-3 shrink-0 text-muted-foreground/70"
          aria-label="Locked"
        />
      ) : null}

      {isEditingTitle ? (
        <CardTitleEdit
          initialTitle={title ?? ""}
          isTentative={tentativeCardId === tree.id}
          validate={(newKey) => validators.cardRename(tree.id, newKey)}
          onCommit={(newKey) => dispatchers.cardRename(tree.id, newKey)}
          onCancel={() => setEditMode(null)}
          onCancelTentative={() => dispatchers.cardCancelTentative(tree.id)}
        />
      ) : (
        <h3
          id={titleId}
          className={cn(
            "min-w-0 flex-1 truncate text-sm font-semibold tracking-tight",
            canRenameTitle && "cursor-text rounded-sm hover:bg-muted px-1 -mx-1",
          )}
          onClick={(e) => {
            e.stopPropagation();
            onSelect({ shiftKey: e.shiftKey, metaKey: e.metaKey, ctrlKey: e.ctrlKey });
            if (canRenameTitle) {
              setEditMode({ kind: "card-title", cardId: tree.id });
            }
          }}
        >
          {title ? (
            <MatchHighlight text={title} ranges={titleRanges} />
          ) : (
            <span className="text-muted-foreground italic font-normal">
              Untitled
            </span>
          )}
        </h3>
      )}

      {showInlineMeta && meta ? (
        <MetaInline meta={meta} metaRenderers={metaRenderers} />
      ) : null}

      {metaPresentation === "popover" && hasMeta && meta ? (
        <MetaPopover
          meta={meta}
          cardId={tree.id}
          editable={editable && canEdit}
          metaRenderers={metaRenderers}
          dispatchers={dispatchers}
          validators={validators}
        />
      ) : null}

      {editable ? (
        <CardActionsMenu
          onRemoveCascade={() => dispatchers.cardRemove(tree.id, "cascade")}
          onRemovePromote={
            defaultDeletePolicy === "promote" || hasChildren
              ? () => dispatchers.cardRemove(tree.id, "promote")
              : undefined
          }
          onDuplicate={
            !isRoot ? () => dispatchers.cardDuplicate(tree.id) : undefined
          }
          canRemove={canRemove}
          canDuplicate={canDuplicate}
          isRoot={isRoot}
          allowRootRemoval={allowRootRemoval}
          hasChildren={hasChildren}
        />
      ) : null}
    </div>
  );
}

import { useEffect, useRef, useState } from "react";
import type { ValidationResult } from "../lib/validate-edit";
import { InlineError } from "./inline-error";

/**
 * Inline editor for a card's parentKey (its visible title).
 * Replaces the <h3> while in edit mode.
 */
export function CardTitleEdit({
  initialTitle,
  validate,
  onCommit,
  onCancel,
  onCancelTentative,
  isTentative,
}: {
  initialTitle: string;
  validate: (newTitle: string) => ValidationResult;
  onCommit: (newTitle: string) => void;
  /** Called on Escape when the card is "real" (not tentative). */
  onCancel: () => void;
  /** Called on Escape when the card was just-added and should be removed. */
  onCancelTentative: () => void;
  isTentative: boolean;
}) {
  const [title, setTitle] = useState(initialTitle);
  const validation = validate(title);
  const ref = useRef<HTMLInputElement>(null);
  useEffect(() => {
    ref.current?.focus();
    ref.current?.select();
  }, []);

  const submit = () => {
    if (validation.ok && title !== initialTitle) onCommit(title);
    else if (title === initialTitle && !isTentative) onCancel();
  };

  const cancel = () => {
    if (isTentative) onCancelTentative();
    else onCancel();
  };

  return (
    <span className="inline-flex flex-1 flex-wrap items-center gap-1">
      <input
        ref={ref}
        type="text"
        value={title}
        onChange={(e) => setTitle(e.target.value)}
        onBlur={submit}
        onKeyDown={(e) => {
          if (e.key === "Enter") {
            e.preventDefault();
            submit();
          } else if (e.key === "Escape") {
            e.preventDefault();
            cancel();
          }
        }}
        className="min-w-0 flex-1 rounded-sm border border-border bg-background px-1.5 py-0.5 text-sm font-semibold tracking-tight focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
        aria-label="Edit card title"
      />
      {!validation.ok ? <InlineError errors={validation.errors} /> : null}
    </span>
  );
}

"use client";

import { type Dispatch } from "react";
import { useSortable } from "@dnd-kit/sortable";
import { CSS } from "@dnd-kit/utilities";
import { cn } from "@/lib/utils";
import type {
  FlatFieldValue,
  LevelStyle,
  MetaRenderer,
  PredefinedKey,
  SearchMatch,
} from "../types";
import type {
  RichCardPredefinedEntry,
  RichCardTree,
} from "../lib/parse";
import type {
  RichCardAction,
  RichCardState,
} from "../lib/reducer";
import type { FlatFieldType } from "../lib/infer-type";
import type { ValidationResult } from "../lib/validate-edit";
import type { EditMode } from "../hooks/use-edit-mode";
import type { UsePermissionsReturn } from "../hooks/use-permissions";
import { CardHeader } from "./card-header";
import { FieldRow } from "./field-row";
import { PredefinedCodeArea } from "./predefined-codearea";
import { PredefinedImage } from "./predefined-image";
import { PredefinedTable } from "./predefined-table";
import { PredefinedQuote } from "./predefined-quote";
import { PredefinedList } from "./predefined-list";
import { PredefinedEdit } from "./predefined-edit";
import { FieldAddButton, FieldAddForm } from "./field-add";
import { PredefinedAddMenu } from "./predefined-add-menu";
