import { useEffect, useRef, useState } from "react";
import { Check, Plus, X } from "lucide-react";
import { cn } from "@/lib/utils";
import type { FlatFieldValue } from "../types";
import type { FlatFieldType } from "../lib/infer-type";
import type { ValidationResult } from "../lib/validate-edit";
import { InlineError } from "./inline-error";

const ADDABLE_TYPES: FlatFieldType[] = [
  "string",
  "number",
  "boolean",
  "date",
];

function defaultValueFor(type: FlatFieldType): FlatFieldValue {
  switch (type) {
    case "number":
      return 0;
    case "boolean":
      return false;
    case "date":
      return new Date().toISOString().slice(0, 10);
    case "null":
      return null;
    case "string":
    default:
      return "";
  }
}

/**
 * Inline form for adding a flat field. Replaces the "+ field" button
 * location while open. Press Enter to add, Escape to cancel.
 */
export function FieldAddForm({
  validateAll,
  onCommit,
  onCancel,
}: {
  validateAll: (
    key: string,
    value: FlatFieldValue,
    type: FlatFieldType,
  ) => ValidationResult;
  onCommit: (
    key: string,
    value: FlatFieldValue,
    type: FlatFieldType,
  ) => void;
  onCancel: () => void;
}) {
  const [key, setKey] = useState("");
  const [type, setType] = useState<FlatFieldType>("string");
  const [value, setValue] = useState<FlatFieldValue>(defaultValueFor("string"));
  const keyRef = useRef<HTMLInputElement>(null);
  useEffect(() => {
    keyRef.current?.focus();
  }, []);

  const validation = validateAll(key, value, type);

  const submit = () => {
    if (validation.ok) {
      onCommit(key, value, type);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter") {
      e.preventDefault();
      submit();
    } else if (e.key === "Escape") {
      e.preventDefault();
      onCancel();
    }
  };

  return (
    <div
      className="space-y-1.5 rounded-md border border-dashed border-border/70 bg-muted/30 p-2"
      onKeyDown={handleKeyDown}
    >
      <div className="grid grid-cols-[minmax(0,auto)_minmax(0,1fr)_minmax(0,auto)] items-center gap-1.5">
        <span className="font-mono text-[10px] uppercase tracking-wider text-muted-foreground">
          key
        </span>
        <input
          ref={keyRef}
          type="text"
          value={key}
          onChange={(e) => setKey(e.target.value)}
          placeholder="field name"
          className="rounded-sm border border-border bg-background px-1.5 py-0.5 font-mono text-[12px] focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
          aria-label="New field key"
        />
        <select
          value={type}
          onChange={(e) => {
            const t = e.target.value as FlatFieldType;
            setType(t);
            setValue(defaultValueFor(t));
          }}
          className="rounded-sm border border-border bg-background px-1.5 py-0.5 font-mono text-[11px] focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
          aria-label="New field type"
        >
          {ADDABLE_TYPES.map((t) => (
            <option key={t} value={t}>
              {t}
            </option>
          ))}
        </select>
      </div>

      <div className="grid grid-cols-[minmax(0,auto)_minmax(0,1fr)] items-center gap-1.5">
        <span className="font-mono text-[10px] uppercase tracking-wider text-muted-foreground">
          value
        </span>
        <ValueInputForType type={type} value={value} onChange={setValue} />
      </div>

      <div className="flex items-center justify-between gap-2">
        {!validation.ok && key.length > 0 ? (
          <InlineError errors={validation.errors} />
        ) : (
          <span />
        )}
        <div className="flex items-center gap-1">
          <button
            type="button"
            onClick={onCancel}
            className="inline-flex size-6 items-center justify-center rounded text-muted-foreground transition-colors hover:bg-muted hover:text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
            aria-label="Cancel add field"
          >
            <X className="size-3.5" aria-hidden="true" />
          </button>
          <button
            type="button"
            onClick={submit}
            disabled={!validation.ok}
            className="inline-flex items-center gap-1 rounded-md bg-primary px-2 py-1 font-mono text-[11px] font-medium text-primary-foreground transition-colors hover:bg-primary/90 disabled:opacity-40 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
          >
            <Check className="size-3" aria-hidden="true" />
            add
          </button>
        </div>
      </div>
    </div>
  );
}

function ValueInputForType({
  type,
  value,
  onChange,
}: {
  type: FlatFieldType;
  value: FlatFieldValue;
  onChange: (v: FlatFieldValue) => void;
}) {
  const baseClass =
    "rounded-sm border border-border bg-background px-1.5 py-0.5 text-[12px] focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring";
  switch (type) {
    case "boolean":
      return (
        <label className="inline-flex items-center gap-1.5 text-sm">
          <input
            type="checkbox"
            checked={value === true}
            onChange={(e) => onChange(e.target.checked)}
            className="size-4 rounded-sm"
          />
          <span className="font-mono text-[11px] text-muted-foreground">
            {value === true ? "true" : "false"}
          </span>
        </label>
      );
    case "number":
      return (
        <input
          type="number"
          value={typeof value === "number" ? String(value) : ""}
          onChange={(e) => {
            const n = Number(e.target.value);
            onChange(Number.isFinite(n) ? n : 0);
          }}
          className={cn(baseClass, "w-32 text-right font-mono tabular-nums")}
          aria-label="New field number value"
        />
      );
    case "date":
      return (
        <input
          type="date"
          value={typeof value === "string" ? value.slice(0, 10) : ""}
          onChange={(e) => onChange(e.target.value)}
          className={cn(baseClass, "min-w-32")}
          aria-label="New field date value"
        />
      );
    case "null":
      return null;
    case "string":
    default:
      return (
        <input
          type="text"
          value={typeof value === "string" ? value : ""}
          onChange={(e) => onChange(e.target.value)}
          placeholder="value"
          className={cn(baseClass, "min-w-32")}
          aria-label="New field string value"
        />
      );
  }
}

/**
 * Lightweight "+ field" button that triggers FieldAddForm.
 */
export function FieldAddButton({
  onClick,
}: {
  onClick: () => void;
}) {
  return (
    <button
      type="button"
      onClick={onClick}
      className="inline-flex items-center gap-1 rounded-md border border-dashed border-border/70 bg-transparent px-2 py-1 font-mono text-[10px] uppercase tracking-wider text-muted-foreground transition-colors hover:bg-muted hover:text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
    >
      <Plus className="size-3" aria-hidden="true" />
      field
    </button>
  );
}

import {
  type ChangeEvent,
  type KeyboardEvent,
  useEffect,
  useRef,
  useState,
} from "react";
import { Check, X } from "lucide-react";
import { cn } from "@/lib/utils";
import type { FlatFieldValue } from "../types";
import type { FlatFieldType } from "../lib/infer-type";
import type { ValidationResult } from "../lib/validate-edit";
import { InlineError } from "./inline-error";

/* ───────── value editor (type-aware) ───────── */

export function FieldValueEdit({
  initialValue,
  type,
  validate,
  onCommit,
  onCancel,
}: {
  initialValue: FlatFieldValue;
  type: FlatFieldType;
  validate: (value: FlatFieldValue) => ValidationResult;
  onCommit: (value: FlatFieldValue) => void;
  onCancel: () => void;
}) {
  const [value, setValue] = useState<FlatFieldValue>(initialValue);
  const validation = validate(value);

  const submit = () => {
    if (validation.ok) onCommit(value);
  };

  const handleKey = (e: KeyboardEvent<HTMLElement>) => {
    if (e.key === "Enter" && type !== "boolean") {
      e.preventDefault();
      submit();
    } else if (e.key === "Escape") {
      e.preventDefault();
      onCancel();
    }
  };

  return (
    <span
      className="inline-flex flex-wrap items-center gap-1"
      onKeyDown={handleKey}
    >
      <ValueInput
        type={type}
        value={value}
        onChange={(v) => {
          setValue(v);
          // For booleans, commit immediately on toggle (Q-P9).
          if (type === "boolean" && validation.ok) {
            onCommit(v);
          }
        }}
        onBlur={() => {
          // Don't commit on blur from boolean — already committed on toggle.
          if (type === "boolean") return;
          submit();
        }}
      />
      {type !== "boolean" ? (
        <span className="inline-flex items-center gap-0.5">
          <button
            type="button"
            onClick={submit}
            disabled={!validation.ok}
            aria-label="Save"
            className="inline-flex size-5 items-center justify-center rounded text-primary transition-colors hover:bg-muted disabled:opacity-40 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
          >
            <Check className="size-3.5" aria-hidden="true" />
          </button>
          <button
            type="button"
            onClick={onCancel}
            aria-label="Cancel"
            className="inline-flex size-5 items-center justify-center rounded text-muted-foreground transition-colors hover:bg-muted focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
          >
            <X className="size-3.5" aria-hidden="true" />
          </button>
        </span>
      ) : null}
      {!validation.ok ? <InlineError errors={validation.errors} /> : null}
    </span>
  );
}

function ValueInput({
  type,
  value,
  onChange,
  onBlur,
}: {
  type: FlatFieldType;
  value: FlatFieldValue;
  onChange: (v: FlatFieldValue) => void;
  onBlur: () => void;
}) {
  const ref = useRef<HTMLInputElement>(null);
  useEffect(() => {
    ref.current?.focus();
    if (ref.current && typeof ref.current.select === "function") {
      try {
        ref.current.select();
      } catch {
        /* some input types don't support select() */
      }
    }
  }, []);

  const baseClass =
    "rounded-sm border border-border bg-background px-1.5 py-0.5 text-sm focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring";

  switch (type) {
    case "boolean":
      return (
        <input
          ref={ref}
          type="checkbox"
          checked={value === true}
          onChange={(e) => onChange(e.target.checked)}
          onBlur={onBlur}
          className="size-4 rounded-sm border border-border focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
          aria-label="Edit boolean value"
        />
      );
    case "number":
      return (
        <input
          ref={ref}
          type="number"
          value={value === null || typeof value !== "number" ? "" : String(value)}
          onChange={(e: ChangeEvent<HTMLInputElement>) => {
            const raw = e.target.value;
            if (raw === "") {
              onChange(0);
              return;
            }
            const n = Number(raw);
            onChange(Number.isFinite(n) ? n : 0);
          }}
          onBlur={onBlur}
          className={cn(baseClass, "w-24 text-right font-mono tabular-nums")}
          aria-label="Edit number value"
        />
      );
    case "date": {
      const isoString = typeof value === "string" ? value : "";
      const hasTime = /T\d{2}:\d{2}/.test(isoString);
      const inputType = hasTime ? "datetime-local" : "date";
      // datetime-local doesn't accept Z-suffix; strip for display
      const inputValue = hasTime
        ? isoString.replace(/Z$/, "").slice(0, 16)
        : isoString.slice(0, 10);
      return (
        <input
          ref={ref}
          type={inputType}
          value={inputValue}
          onChange={(e) => onChange(e.target.value)}
          onBlur={onBlur}
          className={cn(baseClass, "min-w-32")}
          aria-label="Edit date value"
        />
      );
    }
    case "null":
      return (
        <span className="text-muted-foreground italic">
          (read-only — null fields cannot be edited)
        </span>
      );
    case "string":
    default:
      return (
        <input
          ref={ref}
          type="text"
          value={typeof value === "string" ? value : ""}
          onChange={(e) => onChange(e.target.value)}
          onBlur={onBlur}
          className={cn(baseClass, "min-w-32")}
          aria-label="Edit string value"
        />
      );
  }
}

/* ───────── key editor (rename) ───────── */

export function FieldKeyEdit({
  initialKey,
  validate,
  onCommit,
  onCancel,
}: {
  initialKey: string;
  validate: (newKey: string) => ValidationResult;
  onCommit: (newKey: string) => void;
  onCancel: () => void;
}) {
  const [key, setKey] = useState(initialKey);
  const validation = validate(key);
  const ref = useRef<HTMLInputElement>(null);
  useEffect(() => {
    ref.current?.focus();
    ref.current?.select();
  }, []);

  const submit = () => {
    if (validation.ok && key !== initialKey) onCommit(key);
    else if (key === initialKey) onCancel();
  };

  return (
    <span className="inline-flex flex-wrap items-center gap-1">
      <input
        ref={ref}
        type="text"
        value={key}
        onChange={(e) => setKey(e.target.value)}
        onBlur={submit}
        onKeyDown={(e) => {
          if (e.key === "Enter") {
            e.preventDefault();
            submit();
          } else if (e.key === "Escape") {
            e.preventDefault();
            onCancel();
          }
        }}
        className="rounded-sm border border-border bg-background px-1.5 py-0.5 font-mono text-[11px] text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
        aria-label="Rename field key"
      />
      {!validation.ok ? <InlineError errors={validation.errors} /> : null}
    </span>
  );
}

import { Check, Minus, X } from "lucide-react";
import { cn } from "@/lib/utils";
import type { FlatFieldValue, SearchMatch } from "../types";
import type { FlatFieldType } from "../lib/infer-type";
import type { EditMode } from "../hooks/use-edit-mode";
import type { EditDispatchers, EditValidators } from "./card";
import { FieldKeyEdit, FieldValueEdit } from "./field-edit";
import { MatchHighlight } from "./match-highlight";
import { rangesFor } from "../lib/search";

function formatDate(iso: string): string {
  const d = new Date(iso);
  if (Number.isNaN(d.getTime())) return iso;
  const hasTime = /T\d{2}:\d{2}/.test(iso);
  return new Intl.DateTimeFormat(undefined, {
    dateStyle: "medium",
    ...(hasTime ? { timeStyle: "short" } : {}),
  }).format(d);
}

function renderTypedValue(value: FlatFieldValue, type: FlatFieldType, ranges: Array<{ start: number; length: number }>) {
  switch (type) {
    case "null":
      return <span className="text-muted-foreground">—</span>;
    case "boolean":
      return (
        <span className="inline-flex items-center gap-1.5">
          {value === true ? (
            <Check className="size-3.5 text-primary" aria-hidden="true" />
          ) : (
            <Minus className="size-3.5 text-muted-foreground" aria-hidden="true" />
          )}
          <span className="sr-only">{String(value)}</span>
        </span>
      );
    case "number":
      return (
        <span className="font-mono tabular-nums text-foreground/90">
          <MatchHighlight text={String(value)} ranges={ranges} />
        </span>
      );
    case "date":
      return (
        <span title={String(value)} className="text-foreground/90">
          <MatchHighlight text={formatDate(String(value))} ranges={[]} />
        </span>
      );
    case "string":
    default:
      return (
        <span>
          <MatchHighlight text={String(value)} ranges={ranges} />
        </span>
      );
  }
}

export function FieldRow({
  cardId,
  fieldKey,
  value,
  type,
  editable,
  canEdit,
  canEditKey,
  canRemove,
  editMode,
  setEditMode,
  validators,
  dispatchers,
  searchMatches,
  searchQuery,
  searchCaseSensitive,
}: {
  cardId: string;
  fieldKey: string;
  value: FlatFieldValue;
  type: FlatFieldType;
  editable: boolean;
  canEdit: boolean;
  canEditKey: boolean;
  canRemove: boolean;
  editMode: EditMode | null;
  setEditMode: (m: EditMode | null) => void;
  validators: EditValidators;
  dispatchers: EditDispatchers;
  searchMatches: readonly SearchMatch[];
  searchQuery: string;
  searchCaseSensitive: boolean;
}) {
  const isEditingValue =
    editable &&
    canEdit &&
    editMode?.kind === "field-value" &&
    editMode.cardId === cardId &&
    editMode.key === fieldKey;
  const isEditingKey =
    editable &&
    canEditKey &&
    editMode?.kind === "field-key" &&
    editMode.cardId === cardId &&
    editMode.key === fieldKey;

  const canEditValue = editable && canEdit && type !== "null";

  const keyRanges = rangesFor(searchMatches, fieldKey, cardId, "field-key", fieldKey, searchQuery, searchCaseSensitive);
  const valueText = value === null ? "" : String(value);
  const valueRanges = rangesFor(searchMatches, valueText, cardId, "field-value", fieldKey, searchQuery, searchCaseSensitive);

  return (
    <div className="group grid grid-cols-[minmax(0,auto)_minmax(0,1fr)_auto] items-baseline gap-x-3 gap-y-0.5">
      <dt
        className={cn(
          "truncate font-mono text-[11px] text-muted-foreground",
          editable && canEditKey && "cursor-text rounded-sm hover:bg-muted px-1 -mx-1",
        )}
        onClick={() => {
          if (!editable || !canEditKey) return;
          if (isEditingKey) return;
          setEditMode({ kind: "field-key", cardId, key: fieldKey });
        }}
      >
        {isEditingKey ? (
          <FieldKeyEdit
            initialKey={fieldKey}
            validate={(newKey) => validators.fieldEditKey(cardId, fieldKey, newKey)}
            onCommit={(newKey) => dispatchers.fieldEditKey(cardId, fieldKey, newKey)}
            onCancel={() => setEditMode(null)}
          />
        ) : (
          <MatchHighlight text={fieldKey} ranges={keyRanges} />
        )}
      </dt>
      <dd
        className="min-w-0 wrap-break-word text-sm text-foreground"
        onClick={() => {
          if (!canEditValue) return;
          if (isEditingValue) return;
          setEditMode({ kind: "field-value", cardId, key: fieldKey });
        }}
      >
        {isEditingValue ? (
          <FieldValueEdit
            initialValue={value}
            type={type}
            validate={(newValue) =>
              validators.fieldEditValue(cardId, fieldKey, newValue, type)
            }
            onCommit={(newValue) =>
              dispatchers.fieldEditValue(cardId, fieldKey, newValue, type)
            }
            onCancel={() => setEditMode(null)}
          />
        ) : (
          <span
            className={cn(
              canEditValue && "cursor-text rounded-sm hover:bg-muted px-1 -mx-1",
            )}
          >
            {renderTypedValue(value, type, valueRanges)}
          </span>
        )}
      </dd>
      {editable && canRemove ? (
        <button
          type="button"
          onClick={(e) => {
            e.stopPropagation();
            dispatchers.fieldRemove(cardId, fieldKey);
          }}
          aria-label={`Remove field ${fieldKey}`}
          className="inline-flex size-5 items-center justify-center rounded text-muted-foreground opacity-0 transition-all hover:bg-destructive/10 hover:text-destructive group-hover:opacity-100 focus-visible:opacity-100 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
        >
          <X className="size-3" aria-hidden="true" />
        </button>
      ) : (
        <span aria-hidden="true" />
      )}
    </div>
  );
}

import { AlertCircle } from "lucide-react";
import { cn } from "@/lib/utils";
import type { ValidationError } from "../lib/validate-edit";

export function InlineError({
  errors,
  className,
}: {
  errors: ValidationError[];
  className?: string;
}) {
  if (errors.length === 0) return null;
  return (
    <div
      role="alert"
      aria-live="polite"
      className={cn(
        "mt-1 inline-flex items-start gap-1.5 rounded-sm bg-destructive/10 px-1.5 py-0.5 text-[11px] text-destructive",
        className,
      )}
    >
      <AlertCircle className="mt-0.5 size-3 shrink-0" aria-hidden="true" />
      <span>
        {errors.length === 1
          ? errors[0]?.message
          : errors.map((e) => e.message).join(" · ")}
      </span>
    </div>
  );
}

import { Fragment } from "react";
import { cn } from "@/lib/utils";

export type HighlightRange = { start: number; length: number };

/**
 * Wraps matched substrings in <mark>. Active ranges get a distinct style.
 * Non-matched portions render as plain text.
 *
 * Used by every text-rendering location in the tree to display search hits.
 * When `ranges` is empty, this is a transparent passthrough.
 */
export function MatchHighlight({
  text,
  ranges,
  activeRange,
  className,
}: {
  text: string;
  ranges: readonly HighlightRange[];
  activeRange?: HighlightRange;
  className?: string;
}) {
  if (ranges.length === 0) {
    return className ? <span className={className}>{text}</span> : <>{text}</>;
  }
  // Sort and merge ranges
  const sorted = [...ranges].sort((a, b) => a.start - b.start);
  const segments: Array<{
    start: number;
    end: number;
    highlight: boolean;
    isActive: boolean;
  }> = [];
  let cursor = 0;
  for (const r of sorted) {
    if (r.start < cursor) continue; // skip overlapping
    if (r.start > cursor) {
      segments.push({ start: cursor, end: r.start, highlight: false, isActive: false });
    }
    const isActive =
      activeRange !== undefined &&
      activeRange.start === r.start &&
      activeRange.length === r.length;
    segments.push({
      start: r.start,
      end: r.start + r.length,
      highlight: true,
      isActive,
    });
    cursor = r.start + r.length;
  }
  if (cursor < text.length) {
    segments.push({ start: cursor, end: text.length, highlight: false, isActive: false });
  }
  return (
    <span className={className}>
      {segments.map((s, i) => {
        const slice = text.slice(s.start, s.end);
        if (!s.highlight) return <Fragment key={i}>{slice}</Fragment>;
        return (
          <mark
            key={i}
            className={cn(
