function EditorFrame({
  children,
  validation,
  onSave,
  onCancel,
}: {
  children: React.ReactNode;
  validation: ValidationResult;
  onSave: () => void;
  onCancel: () => void;
}) {
  return (
    <div
      className="space-y-1.5 rounded-md border border-dashed border-primary/40 bg-muted/40 p-2"
      onKeyDown={(e) => {
        if (e.key === "Escape") {
          e.preventDefault();
          onCancel();
        }
